-- Perfume data collected by AGENTE 2

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('59d28526-b510-490d-97ff-7db4d339a93b', 'Interlude 53 Man', 'Amouage', 2020, 'Extrait de Parfum', 'Oregano, Pimento, Bergamot', 'Incense, Amber, Opoponax, Labdanum', 'Smoke, Agarwood (Oud), Leather, Patchouli, Sandalwood', 'Interlude 53 Extrait pays homage to Interlude Man, reimagining it as an extrait de parfum of unrivalled intensity. Resolutely bold, its opening accord of spicy oregano and balsamic labdanum creates a powerful smoky prelude to a complex heart of incense and opoponax.', 'https://fimgs.net/mdimg/perfume/375x500.64419.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('c21f3522-5040-47f9-a0f1-0aa1703035f2', 'Aventus', 'Creed', 2010, 'Eau de Parfum', 'Pineapple, Bergamot, Blackcurrant Leaves, Apple', 'Birch, Patchouli, Moroccan Jasmine, Rose', 'Musk, Oak Moss, Ambergris, Vanilla', 'Aventus celebrates strength, power and success, inspired by the dramatic life of a historic emperor. This sophisticated scent for him has become a classic and a must-have for every modern gentleman.', 'https://fimgs.net/mdimg/perfume/375x500.9828.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('369f960d-b6a2-4f90-9f6c-837e430a92e1', 'Sauvage Elixir', 'Dior', 2021, 'Elixir', 'Nutmeg, Cinnamon, Cardamom, Grapefruit', 'Lavender', 'Licorice, Sandalwood, Amber, Patchouli, Haitian Vetiver', 'Sauvage Elixir is a concentrated and precious interpretation of Dior''s iconic men''s fragrance. It concentrates all of its power in an intense and smooth formula. This ambery scent is filled with spices, layered with lavender and enriched with a rich, dark base.', 'https://fimgs.net/mdimg/perfume/375x500.75525.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('8fea7e8b-ca23-412b-8ee3-819a289b8175', 'Tobacco Vanille', 'Tom Ford', 2007, 'Eau de Parfum', 'Tobacco Leaf, Spicy Notes, Ginger', 'Tobacco Blossom, Cacao, Tonka Bean, Vanilla', 'Dry Fruit Notes, Woody Notes', 'Tom Ford''s Tobacco Vanille is opulent, warm and iconic. Reminiscent of an English gentleman''s club, blending Indian tobacco leaf and vanilla with a hint of cocoa, tonka bean, tobacco flower, ginger, and dried fruits.', 'https://fimgs.net/mdimg/perfume/375x500.1825.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('e14d0b41-36a8-4ef5-96de-9e98b14b4406', 'Layton', 'Parfums de Marly', 2016, 'Eau de Parfum', 'Apple, Lavender, Mandarin Orange, Bergamot', 'Geranium, Violet, Jasmine', 'Vanilla, Cardamom, Sandalwood, Pepper, Guaiac Wood, Patchouli', 'Layton is an elegant and sophisticated fragrance that combines fresh, fruity top notes with a warm, spicy heart and a rich, vanilla-laden base. Named after the English horse racing town, it exudes British elegance and refinement.', 'https://fimgs.net/mdimg/perfume/375x500.39241.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('231f0f0c-a632-4150-89f2-39f45bf5ff22', 'Baccarat Rouge 540', 'Maison Francis Kurkdjian', 2015, 'Extrait de Parfum', 'Saffron, Jasmine', 'Amberwood, Ambergris', 'Fir Resin, Cedar', 'Baccarat Rouge 540 is a luminous and sophisticated floral woody amber fragrance. The grandiflorum jasmine from Egypt, saffron, amberwood and ambergris accord create a bright and elegant scent trail.', 'https://fimgs.net/mdimg/perfume/375x500.34513.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('f5edf108-7e1a-48ba-98f0-93b790096493', 'Oud for Greatness', 'Initio', 2018, 'Eau de Parfum Haute Concentration', 'Saffron, Lavender, Nutmeg', 'Agarwood (Oud)', 'Musk', 'Oud for Greatness is a lavish oriental-spicy fragrance built around the finest natural oud. Combined with saffron, lavender, and musk, it creates an aura of power and mystique.', 'https://fimgs.net/mdimg/perfume/375x500.54204.jpg');

INSERT INTO perfumes (id, name, brand, year, type, notes_top, notes_heart, notes_base, description, image_url) 
VALUES ('cb98ce62-6c73-4027-9eb7-e4cd60182213', 'Naxos', 'Xerjoff', 2015, 'Eau de Parfum', 'Lavender, Bergamot, Lemon', 'Honey, Cinnamon, Jasmine Sambac', 'Tobacco Leaf, Vanilla, Tonka Bean, Cashmeran', 'Naxos is inspired by the ancient Greek island. A gourmand oriental fragrance with honey, lavender, and tobacco, creating a warm and sophisticated scent.', 'https://fimgs.net/mdimg/perfume/375x500.34519.jpg');


